"""Test Python RS algorithm with exact same data as R."""

import numpy as np
import pandas as pd
import sys
sys.path.insert(0, 'omnilss/src')

from omnilss import gamlss

# Load data generated by R
df = pd.read_csv("scripts/diagnostic/test_data_nbi.csv")
y = df['y'].values
x1 = df['x1'].values

data = {
    'y': y,
    'x1': x1
}

print("=" * 70)
print("Testing Python RS Algorithm with R-generated data")
print("=" * 70)
print(f"Sample size: {len(y)}")
print(f"Formula: y ~ x1")
print(f"Family: NBI")
print("=" * 70)

# Fit model with RS algorithm
model = gamlss(
    formula="y ~ x1",
    sigma_formula="~1",
    family="NBI",
    data=data,
    method="RS",
    verbose=True
)

print("\n" + "=" * 70)
print("Python Results:")
print("=" * 70)
print(f"Global Deviance: {model.g_dev:.6f}")
print(f"Iterations: {model.iter}")
print(f"Converged: {model.additional_slots.get('converged', False)}")
print("\nMu coefficients:")
print(f"  Intercept: {model.coefficients['mu'][0]:.6f}")
print(f"  x1: {model.coefficients['mu'][1]:.6f}")
print("\nSigma:")
print(f"  Log(sigma): {model.coefficients['sigma'][0]:.6f}")
print(f"  Sigma: {np.exp(model.coefficients['sigma'][0]):.6f}")
print("=" * 70)

# Load R results
r_params = pd.read_csv("scripts/diagnostic/r_fitted_params.csv")
r_deviance = r_params[r_params['parameter'] == 'deviance']['value'].values[0]
r_mu_int = r_params[r_params['parameter'] == 'mu_intercept']['value'].values[0]
r_mu_x1 = r_params[r_params['parameter'] == 'mu_x1']['value'].values[0]
r_sigma_log = r_params[r_params['parameter'] == 'sigma_log']['value'].values[0]
r_sigma = r_params[r_params['parameter'] == 'sigma']['value'].values[0]

print("\nR Results (for comparison):")
print("=" * 70)
print(f"Global Deviance: {r_deviance:.6f}")
print("\nMu coefficients:")
print(f"  Intercept: {r_mu_int:.6f}")
print(f"  x1: {r_mu_x1:.6f}")
print("\nSigma:")
print(f"  Log(sigma): {r_sigma_log:.6f}")
print(f"  Sigma: {r_sigma:.6f}")
print("=" * 70)

print("\nDifferences:")
print("=" * 70)
print(f"Deviance diff: {model.g_dev - r_deviance:.6f}")
print(f"Mu intercept diff: {model.coefficients['mu'][0] - r_mu_int:.6f}")
print(f"Mu x1 diff: {model.coefficients['mu'][1] - r_mu_x1:.6f}")
print(f"Sigma diff: {np.exp(model.coefficients['sigma'][0]) - r_sigma:.6f}")
print("=" * 70)
